		});

		showAlert("Email added.", "success");
		await Promise.allSettled([qMemberEmails.run(), qMemberById.run()]);
		resetWidget("frmAddMemberEmail", true);
	},

	async addMemberPhone() {
		const memberId = appsmith.store.member_id;

		const res = await qAddMemberPhone.run({
			member_id: memberId,
			phone: inpNewMemberPhone.text,
			is_primary: chkNewMemberPhonePrimary.isChecked,
			notes: inpNewMemberPhoneNotes.text
		});

		const row = Array.isArray(res) ? res[0] : res;

		await this.auditLog("member.phone.added", "member", memberId, {
			member_id: memberId,
			member_phone_id: row?.member_phone_id || null,
			phone: inpNewMemberPhone.text,
			is_primary: chkNewMemberPhonePrimary.isChecked,
			notes: inpNewMemberPhoneNotes.text || null
		});

		showAlert("Phone added.", "success");
		await Promise.allSettled([qMemberPhones.run(), qMemberById.run()]);
		resetWidget("frmAddMemberPhone", true);
	},

	async addMemberAddress() {
		const memberId = appsmith.store.member_id;

		const res = await qAddMemberAddress.run({
			member_id: memberId,
			address_type: inpNewMemberAddressType?.text || "home",
			address_1: inpNewMemberAddress1.text,
			address_2: inpNewMemberAddress2.text,
			city: inpNewMemberCity.text,
			state: inpNewMemberState.text,
			postal_code: inpNewMemberPostalCode.text,
			country: inpNewMemberCountry.text || "USA",
			is_primary: chkNewMemberAddressPrimary.isChecked,
			notes: inpNewMemberAddressNotes.text
		});

		const row = Array.isArray(res) ? res[0] : res;

		await this.auditLog("member.address.added", "member", memberId, {
			member_id: memberId,
			member_address_id: row?.member_address_id || null,
			address_1: inpNewMemberAddress1.text,
			address_2: inpNewMemberAddress2.text || null,
			city: inpNewMemberCity.text,
			state: inpNewMemberState.text,
			postal_code: inpNewMemberPostalCode.text,
			country: inpNewMemberCountry.text || "USA",
			is_primary: chkNewMemberAddressPrimary.isChecked,
			notes: inpNewMemberAddressNotes.text || null
		});

		showAlert("Address added.", "success");
		await Promise.allSettled([qMemberAddresses.run(), qMemberById.run()]);
		resetWidget("frmAddMemberAddress", true);
	},

	async archiveMemberEmail(row, reason = "Archived from Members - Profile") {
		const oldMemberId = row.member_id || appsmith.store.member_id;

		const res = await qArchiveMemberEmail.run({
			member_email_id: row.member_email_id,
			reason
		});

		await this.auditLog("member.email.archived", "member", oldMemberId, {
			member_id: oldMemberId,
			member_email_id: row.member_email_id,
			email: row.email,
			reason
		});

		showAlert("Email archived.", "success");
