	_normalizeUploadResponse(uploadRes) {
		const r = uploadRes?.data ?? uploadRes;

		const arr =
			Array.isArray(r) ? r :
			Array.isArray(r?.files) ? r.files :
			(r && typeof r === "object") ? [r] :
			[];

		// Require real attachment objects (path or signedPath)
		const good = arr.filter(x => x && (x.path || x.signedPath));

		if (!good.length) {
			console.log("Unexpected upload response:", uploadRes);
			throw new Error("Upload succeeded but did not return attachment path(s).");
		}

		return good;
	},

	async linkPendingGivebutterDonation() {
		try {
			if (!appsmith.store.facilitator_is_donations_reviewer) {
				showAlert("Only donations reviewers can link Givebutter donations.", "error");
				return;
			}

			const donation = tblPendingGivebutterDonations.selectedRow;
			const memberId = selDonationMember.selectedOptionValue;
			const notes = inpDonationNotes.text || "";

			if (!donation?.donation_id) {
				showAlert("Select a pending Givebutter donation.", "warning");
				return;
			}

			if (!memberId) {
				showAlert("Select the member to link this donation to.", "warning");
				return;
			}

			let raw = donation.details?.raw || donation.raw || {};
			if (typeof raw === "string") {
				raw = JSON.parse(raw || "{}");
			}
			const data = raw.data || raw;

			await qLinkDonationToMember.run({
				donation_id: donation.donation_id,
				member_id: memberId,
				review_notes: notes
			});

			if (data.email) {
				await qAddGivebutterEmailToMember.run({
					member_id: memberId,
					email: data.email,
					subscribe_to_mailing_list: chkGivebutterSubscribeListmonk.isChecked
				});
			}

			if (data.phone) {
				await qAddGivebutterPhoneToMember.run({
					member_id: memberId,
					phone: data.phone
				});
			}

			if (data.address?.address_1) {
				await qAddGivebutterAddressToMember.run({
					member_id: memberId,
					address_1: data.address.address_1,
					address_2: data.address.address_2 || "",
					city: data.address.city || "",
					state: data.address.state || "",
					postal_code: data.address.zipcode || data.address.postal_code || "",
					country: data.address.country || "USA"
				});
			}

			await cashDonationFlows.auditLog("donation.givebutter.linked", "donation", donation.donation_id, {
				donation_id: donation.donation_id,
				member_id: memberId,
				provider_reference: donation.provider_reference,
				review_notes: notes,
				added_email: data.email || null,
				added_phone: data.phone || null,
				added_address: data.address || null
			});

			showAlert("Givebutter donation linked.", "success");

			await Promise.allSettled([
				qPendingGivebutterDonations.run(),
				qMembersDirectory.run()
			]);
		} catch (e) {
			showAlert("Failed to link Givebutter donation: " + (e?.message || e), "error");
			throw e;
		}
	},

	async submitDonation() {
		showAlert("Recording cash donation.", "success");
		const member_id = selDonationMember.selectedOptionValue || appsmith.URL.queryParams.member_id;

		if (!member_id) { 
			showAlert("Select a member first.", "warning"); 
			return; 
		}

		const amount = Number(inpDonationAmount.text);

		if (!amount || amount <= 0) { 
				showAlert("Enter a positive amount.", "warning"); 
				return; 
		}

		const amount_cents = Math.round(amount * 100);
		const donated_at = inpDonationDate.selectedDate || moment().format("YYYY-MM-DD");
		const notes = inpDonationNotes.text || "";


		const res = await qInsertCashDonation.run({ member_id, amount_cents, donated_at, notes });
		const donation_id = (Array.isArray(res) && res[0] && (res[0].donation_id || res[0].id)) ? (res[0].donation_id || res[0].id) : "";

		await cashDonationFlows.auditLog("donation.cash.created", "donation", donation_id, { member_id, amount_cents, donated_at, notes });

		showAlert("Cash donation recorded (pending review).", "success");

		return donation_id;

	},

	async ignorePendingDonation() {
		const donation = tblPendingGivebutterDonations.selectedRow;
		const notes = inpDonationNotes.text || "Donation does not apply to a member";

		if (!donation?.donation_id) {
			showAlert("Select a pending donation.", "warning");
			return;
		}

		const row = (await qIgnorePendingDonation.run({
			donation_id: donation.donation_id,
			review_notes: notes
		}))?.[0];

		await this.auditLog("donation.ignored", "donation", donation.donation_id, {
			donation_id: donation.donation_id,
			provider: donation.provider,
			provider_reference: donation.provider_reference,
			review_notes: notes,
			ignored_by: appsmith.store.facilitator_id
		});

		showAlert("Donation ignored.", "success");
		await qPendingGivebutterDonations.run();
	},

	async createMemberFromPendingDonation() {
		const donation = tblPendingGivebutterDonations.selectedRow;
		const notes = inpDonationNotes.text || "Created member from Givebutter donation";

		if (!appsmith.store.facilitator_is_donations_reviewer) {
			showAlert("Only donations reviewers can create members from donations.", "error");
			return;
		}

		if (!donation?.donation_id) {
			showAlert("Select a pending Givebutter donation.", "warning");
			return;
		}

		const created = await qCreateMemberFromDonation.run({
			donation_id: donation.donation_id,
			review_notes: notes,
			subscribe_to_mailing_list: chkGivebutterSubscribeListmonk.isChecked
		});

		const member = created?.[0];

		if (!member?.member_id) {
			showAlert("Member was not created.", "error");
			return;
		}

		await this.auditLog("donation.member_created", "donation", donation.donation_id, {
			donation_id: donation.donation_id,
			provider: donation.provider,
			provider_reference: donation.provider_reference,
			created_member_id: member.member_id,
			created_member_name: `${member.first_name || ""} ${member.last_name || ""}`.trim(),
			email: member.email || null,
			phone: member.phone || null,
			review_notes: notes
		});

		await this.auditLog("member.created_from_donation", "member", member.member_id, {
			member_id: member.member_id,
			donation_id: donation.donation_id,
			provider: donation.provider,
			provider_reference: donation.provider_reference,
			review_notes: notes
		});

		showAlert("Member created and donation linked.", "success");

		await Promise.allSettled([
			qPendingGivebutterDonations.run(),
