      let _attCount = 0;
      try {
        const _ev = evidence_json ? JSON.parse(evidence_json) : [];
        _attCount = Array.isArray(_ev) ? _ev.length : 0;
      } catch (e) {}
      await memberFlows.auditLog("member_agreement.evidence_uploaded", "member_agreement", _agId2, {
        member_id: memberId,
