    showAlert("Email was not added. It is already active on another member; use the Reassign Email action from the existing row if that is intentional.", "warning");
    return;
  }
  await memberProfile.auditLog("member.email.added", "member", memberId, {
    member_id: memberId,
    member_email_id: row?.member_email_id || null,
    email: inpNewMemberEmail.text,
    is_primary: chkNewMemberEmailPrimary.isChecked,
    mailing_subscription_status: row?.mailing_subscription_status || null,
    notes: inpNewMemberEmailNotes.text || null
  });
  showAlert("Email added.", "success");
  await Promise.allSettled([qMemberEmails.run(), qMemberById.run()]);
  resetWidget("frmAddMemberEmail", true);
}

