function (oldObj, newObj) {
  const changes = {};
  for (const k of Object.keys(newObj)) {
    const a = oldObj?.[k];
    const b = newObj?.[k];
    const na = a === null || a === undefined ? "" : String(a);
    const nb = b === null || b === undefined ? "" : String(b);
    if (na !== nb) changes[k] = {
      from: a ?? null,
      to: b ?? null
    };
  }
  return changes;
}

