async function () {
  const member_id = String(selMember.selectedOptionValue || appsmith.store.member_id || "").trim() || null;
  const release_type = selReleaseType.selectedOptionValue || "sacrament_release";
  const storage_location_name = tblProducts.selectedRow.storage_location || null;
  if (!storage_location_name) {
    showAlert("Internal error: unknown storage location.", "warning");
    return;
  }
  if (!member_id) {
    showAlert("Select a member.", "warning");
    return;
  }
  await releaseFlows.auditLog("release.attempt", "member", member_id, {
    member_id,
    release_type,
    page: appsmith.URL?.pathname
  });
  const gateRows = await qGateCheckAgreement.run({
    member_id,
    release_type
  });
  const gateRow = Array.isArray(gateRows) && gateRows.length > 0 ? gateRows[0] : null;
  const hasAgreement = !!gateRow?.member_agreement_id;
  const isReviewer = appsmith.store.facilitator_is_reviewer === true || appsmith.store.facilitator_is_reviewer === "true";
  const notes = inpNotes.text || "";
  const reviewerOverride = !hasAgreement && isReviewer;
  if (!hasAgreement && !isReviewer) {
    showAlert("Not eligible. Member must sign the required agreement before a release can be issued.", "error");
    return;
  }
  if (reviewerOverride && !notes.trim()) {
    showAlert("Notes are required when a document reviewer issues a release without a signed agreement.", "warning");
    return;
  }
  const product = tblProducts.selectedRow;
  if (release_type === "sacrament_release") {
    if (!product?.mushroomprocess_product_id) {
      showAlert("Select a product to issue.", "warning");
      return;
    }
  }
  const facilitator_id = selFacilitator.selectedOptionValue || null;
  if (!facilitator_id) {
    showAlert("Select a facilitator.", "warning");
    return;
  }
  const quantity = 1;
  if (!Number.isFinite(quantity) || quantity <= 0) {
    showAlert("Quantity must be a positive number.", "warning");
    return;
  }
  const unit = "g";
  if (release_type === "sacrament_release") {
    await apiMarkProductShipped.run();
  }
  showAlert(`Shipped: ${product?.mushroomprocess_product_id || "ok"}`, "success");
  const ins = await qCreateRelease.run({
    member_id: member_id,
    release_type: release_type,
    member_agreement_id: gateRow?.member_agreement_id || null,
    mushroomprocess_product_id: product?.mushroomprocess_product_id || null,
    item_name: product?.item_name || release_type,
    quantity: quantity,
    unit: unit,
    net_weight_g: product?.net_weight_g.replace(/[a-zA-Z]+$/, "") || null,
    strain: product?.strain || null,
    facilitator_id: facilitator_id,
    storage_location_name: storage_location_name,
    agreement_override: reviewerOverride,
    override_reason: reviewerOverride ? notes : null,
    override_by: reviewerOverride ? appsmith.store.facilitator_id : null,
    notes: notes
  });
  showAlert(`Release issued: ${ins?.[0]?.sacrament_release_id || "ok"}`, "success");
  await releaseFlows.auditLog("release.issued", "release", ins?.[0]?.sacrament_release_id, {
    member_id: member_id,
    release_type: release_type,
    member_agreement_id: gateRow?.member_agreement_id || null,
    mushroomprocess_product_id: product?.mushroomprocess_product_id || null,
    item_name: product?.item_name || release_type,
    quantity: quantity,
    unit: unit,
    net_weight_g: product?.net_weight_g.replace(/[a-zA-Z]+$/, "") || null,
    strain: product?.strain || null,
    facilitator_id: facilitator_id,
    storage_location_name: storage_location_name,
    notes: notes
  });
  if (release_type === "sacrament_release") {
    await apiListAvailableProducts.run();
  }
  return ins;
}

