    item_name: product?.item_name || release_type,
    quantity: quantity,
    unit: unit,
    net_weight_g: product?.net_weight_g.replace(/[a-zA-Z]+$/, "") || null,
    strain: product?.strain || null,
    facilitator_id: facilitator_id,
    storage_location_name: storage_location_name,
    agreement_override: reviewerOverride,
    override_reason: reviewerOverride ? notes : null,
    override_by: reviewerOverride ? appsmith.store.facilitator_id : null,
    notes: notes
  });
