actionConfiguration.body:
async function () {
  const donation = tblPendingGivebutterDonations.selectedRow;
  const notes = inpDonationNotes.text || "Created member from Givebutter donation";
  if (!appsmith.store.facilitator_is_donations_reviewer) {
    showAlert("Only donations reviewers can create members from donations.", "error");
    return;
  }
  if (!donation?.donation_id) {
    showAlert("Select a pending Givebutter donation.", "warning");
    return;
  }
  const created = await qCreateMemberFromDonation.run({
    donation_id: donation.donation_id,
    review_notes: notes,
    subscribe_to_mailing_list: chkGivebutterSubscribeListmonk.isChecked
  });
  const member = created?.[0];
  if (!member?.member_id) {
    showAlert("Member was not created.", "error");
    return;
  }
  await cashDonationFlows.auditLog("donation.member_created", "donation", donation.donation_id, {
    donation_id: donation.donation_id,
    provider: donation.provider,
    provider_reference: donation.provider_reference,
    created_member_id: member.member_id,
    created_member_name: `${member.first_name || ""} ${member.last_name || ""}`.trim(),
    email: member.email || null,
    phone: member.phone || null,
    review_notes: notes
  });
  await cashDonationFlows.auditLog("member.created_from_donation", "member", member.member_id, {
    member_id: member.member_id,
    donation_id: donation.donation_id,
    provider: donation.provider,
    provider_reference: donation.provider_reference,
    review_notes: notes
  });
  showAlert("Member created and donation linked.", "success");
  await Promise.allSettled([qPendingGivebutterDonations.run(), qMembersDirectory.run()]);
  navigateTo("Members - Profile", {
    member_id: member.member_id
  }, "SAME_WINDOW");
}

