actionConfiguration.body:
function (raw) {
  const t = raw?.json || raw || ({});
  const recipients = Array.isArray(t.recipients) ? t.recipients.slice() : [];
  const signerRecipients = recipients.filter(r => String(r.role || "").toUpperCase() === "SIGNER" || r.signingOrder).sort((a, b) => (agreementTemplateFlows._normInt(a.signingOrder) ?? 999) - (agreementTemplateFlows._normInt(b.signingOrder) ?? 999));
  const memberRecipient = signerRecipients.find(r => agreementTemplateFlows._normInt(r.signingOrder) === 1) || signerRecipients[0] || null;
  const facilitatorRecipient = signerRecipients.find(r => agreementTemplateFlows._normInt(r.signingOrder) === 2) || signerRecipients[1] || null;
  return {
    template_id: agreementTemplateFlows._normInt(t.id ?? t.templateId ?? t.template_id),
    envelope_id: agreementTemplateFlows._normText(t.envelopeId ?? t.envelope_id ?? t.id),
    title: agreementTemplateFlows._normText(t.title ?? t.name ?? t.envelopeId ?? t.id),
    type: agreementTemplateFlows._normText(t.type),
    recipient_count: recipients.length,
    member_recipient_id: agreementTemplateFlows._normInt(memberRecipient?.id),
    facilitator_recipient_id: agreementTemplateFlows._normInt(facilitatorRecipient?.id),
    recipients
  };
}

