function () {
  const selected = reports.selectedMetricKeys();
  if (!selected.length) {
    showAlert("Select at least one data set.", "warning");
    return false;
  }
  const periods = reports.normalizePeriods();
  if (periods > reports.MAX_BUCKETS) {
    showAlert(`Please limit the report to ${reports.MAX_BUCKETS} buckets or fewer.`, "warning");
    return false;
  }
  if (reports.hasCustomRange()) {
    const start = new Date(dpReportStart.selectedDate);
    const end = new Date(dpReportEnd.selectedDate);
    if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
      showAlert("Invalid start or end date.", "warning");
      return false;
    }
    if (start > end) {
      showAlert("Start date must be before end date.", "warning");
      return false;
    }
  }
  return true;
}

