jsonPathKeys:
function () {
  const rows = qReportTimeSeries.data || [];
  const metricKeys = reports.selectedMetricKeys();
  const metricMeta = Object.fromEntries(reports.metricOptions().map(x => [x.value, x]));
  const bucketLabels = [...new Set(rows.map(r => r.bucket_label))];
  const series = metricKeys.map(metricKey => {
    const meta = metricMeta[metricKey] || ({
      label: metricKey,
      value: metricKey
    });
    return {
      name: meta.label,
      type: "bar",
      data: bucketLabels.map(label => {
        const row = rows.find(r => r.bucket_label === label && r.metric_key === metricKey);
        return Number(row?.value || 0);
      })
    };
  });
  return {
    tooltip: {
      trigger: "axis",
      axisPointer: {
        type: "shadow"
      }
    },
    legend: {
      type: "scroll",
      top: 0
    },
    grid: {
      left: 70,
      right: 30,
      bottom: bucketLabels.length > 16 ? 90 : 50,
      top: 60,
      containLabel: true
    },
    xAxis: {
      type: "category",
      data: bucketLabels,
      axisLabel: {
        rotate: bucketLabels.length > 16 ? 45 : 0
      }
    },
    yAxis: {
      type: "value"
    },
    series
  };
}

