children.text:
{{
(() => {
  const selectedMember = String(
    selMember.selectedOptionValue ||
    appsmith.store.member_id ||
    ""
  ).trim();

  const memberRow = (qMembersDirectory.data || [])
    .find(m => String(m.member_id) === selectedMember);

  const memberLabel = memberRow
    ? `${memberRow.first_name || ""} ${memberRow.last_name || ""}`.trim()
    : selectedMember || "selected member";

  const releaseType = selReleaseType.selectedOptionValue || "sacrament_release";

  const releaseTypeRow = (qAgreementTypesList.data || [])
    .find(t => String(t.type_key) === String(releaseType));

  const releaseLabel =
    releaseTypeRow?.display_name ||
    releaseType ||
    "selected release type";

  if (!selectedMember) {
    return "Select a member to check eligibility.";
  }

  if (qGateCheckAgreement.isLoading) {
    return "Checking eligibility...";
  }

  const gateRow = qGateCheckAgreement.data?.[0] || null;

  if (gateRow?.member_agreement_id) {
    const signedLabel =
      gateRow.template_name ||
      releaseLabel ||
      "required agreement";

    return `✅ Eligible — ${memberLabel} has signed: ${signedLabel}`;
  }

  return `❌ Not eligible — ${memberLabel} has not signed: ${releaseLabel}`;
})()
}}

